        html[system-icons][dark],
        html[system-icons] [dark] {
            --yt-spec-icon-disabled: var(--disabled-color);
            --yt-spec-brand-icon-inactive: var(--main-text);
            --yt-spec-icon-inactive: var(--main-text);
        }

        /* Text selection */
        html[dark] {
            ::selection {
                color: var(--black, var(--white, var(--main-background))) !important;
                background: var(--main-color) !important;
            }

            /* Tooltip */
            .tp-yt-paper-tooltip[style-target=tooltip] {
                color: var(--black, var(--white, var(--main-background)));
            }

            /* Input fields */
            ::-webkit-input-placeholder {
                color: var(--secondary-text) !important;
            }

            ytd-searchbox[has-focus] #container.ytd-searchbox {
                border: none;
                box-shadow: none;
            }

            .focused-line.tp-yt-paper-input-container,
            input:focus,
            yt-clip-creation-scrubber-renderer[highlight-start] #start.yt-clip-creation-scrubber-renderer,
            yt-clip-creation-scrubber-renderer[highlight-end] #end.yt-clip-creation-scrubber-renderer {
                border-color: var(--main-color);
            }

            .unfocused-line.tp-yt-paper-input-container {
                border-color: var(--button-hover-color);
            }

            #bar.yt-copy-link-renderer,
            yt-copy-link-renderer[renderer-style=copy-link-renderer-style-settings] #bar.yt-copy-link-renderer {
                background: var(--button-color);
                border: none;
            }

            /* Dropdown menus */
            ytd-dropdown-renderer {
                --paper-dropdown-menu-focus-color: var(--main-color);
            }

            /* Search suggestions box */
            .sbsb_a {
                background: var(--button-solid-color);
            }

            .gsfs,
            .sbpqs_a b,
            .sbpqs_a,
            .sbfl_a:hover {
                color: var(--main-text);
            }

            .sbsb_i {
                color: var(--main-color);
            }

            .sbqs_c::before,
            .sbpqs_a::before,
            ytd-masthead .gsst_e {
                filter: var(--filter);
            }

            .sbpqs_a::before {
                background: no-repeat url('data:image/svg+xml;base64,');
            }

            .sbqs_c::before {
                background: no-repeat url('data:image/svg+xml;base64,');
            }

            .sbfl_b {
                background: none;
            }

            .sbpqs_c {
                color: var(--secondary-text);
            }

            /* Regular/Shorts player */
            .ytp-play-progress,
            .ytp-swatch-background-color:not(.ytp-play-progress),
            #progress.ytd-thumbnail-overlay-resume-playback-renderer,
            .ytp-chrome-controls .ytp-button[aria-pressed]:after,
            .ytp-slider-handle,
            .ytp-slider-handle:before,
            .ytp-menuitem[aria-checked=true] .ytp-menuitem-toggle-checkbox:after,
            .ytp-volume-slider-handle:before,
            .ytp-volume-slider-handle {
                background: var(--main-color);
            }

            .ytp-slider-handle:after {
                background: var(--button-hover-color);
                z-index: -1;
            }

            .ytp-volume-slider-handle:after {
                z-index: -1;
            }

            .ytp-probably-keyboard-focus {           
                .ytp-progress-bar:focus {
                    box-shadow: 0 0 0 2px var(--main-color);
                }

                .ytp-button:focus,
                .ytp-volume-panel:focus,
                .ytp-panel-footer-content-link:focus,
                .ytp-slider-section:focus {
                    box-shadow: inset 0 0 0 2px currentcolor;
                }                

                .ytp-panel-back-button:focus {
                    box-shadow: inset 0 0 0 2px black;
                }

                .ytp-menuitem:focus {
                    .ytp-menuitem-icon, 
                    .ytp-menuitem-label:first-child {
                        box-shadow: inset 2px 2px 0 currentcolor, inset 0 -2px 0 currentcolor;
                    }
                    .ytp-menuitem-label {
                        box-shadow: inset 0 2px 0 currentcolor, inset 0 -2px 0 currentcolor;
                    }
                    .ytp-menuitem-content {
                        box-shadow: inset -2px -2px 0 currentcolor, inset 0 2px 0 currentcolor;
                    }
                }

                .ytp-menuitem[role=menuitemradio]:focus .ytp-menuitem-label {
                    box-shadow: inset 2px 2px 0 currentcolor, inset -2px -2px 0 currentcolor;
                }
            }

            .html5-video-player .ytp-panel-footer-content-link {
                color: var(--main-color);
            }

            .ytp-popup {
                background: var(--button-solid-color);
            }

            .ytp-panel-menu,
            .ytp-panel-header,
            .ytp-quality-menu .ytp-menuitem-label supm,
            .ytp-panel-footer,
            .html5-video-player .ytp-popup {
                color: var(--main-text);
            }

            .ytp-menuitem-label-count,
            .ytp-menu-label-secondary,
            .ytp-swatch-color-white,
            .ytp-premium-label {
                color: var(--secondary-text);
            }

            .ytp-menuitem-icon [fill="white"],
            .ytp-menuitem-icon [fill*="fff"] {
                fill: var(--main-text);
            }

            .ytp-menuitem[aria-haspopup=true] .ytp-menuitem-content {
                background-image: var(--arrow);
            }

            .ytp-menuitem[role=menuitemradio][aria-checked=true] .ytp-menuitem-label,
            .ytp-contextmenu .ytp-menuitem[aria-checked=true] .ytp-menuitem-toggle-checkbox {
                background-image: var(--check-mark);
            }

            .ytp-panel-back-button {
                background-image: url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSIxMDAlIiBoZWlnaHQ9IjEwMCUiIHZpZXdCb3g9IjAgMCAzMiAzMiIgdmVyc2lvbj0iMS4xIj48cGF0aCBkPSJNIDE5LjQxLDIwLjA5IDE0LjgzLDE1LjUgMTkuNDEsMTAuOTEgMTgsOS41IGwgLTYsNiA2LDYgeiIgZmlsbD0iYmxhY2siIC8+PC9zdmc+');
                filter: var(--filter);
            }

            .ytp-popup {
                text-shadow: none;
            }

            .ytp-panel-header,
            .ytp-panel-footer {
                border-color: var(--button-hover-color);
            }

            .ytp-menuitem:not([aria-disabled=true]):hover {
                background: var(--button-hover-color);
            }

            .ytp-tooltip-text:not(.ytp-preview:not(.ytp-text-detail) .ytp-tooltip-text) {
                background: var(--main-color);
                color: var(--black, var(--white, var(--main-background)));
            }

            .iv-branding .branding-context-container-inner {
                background: var(--main-background);
                color: var(--main-text);
            }

            .ytp-tooltip.ytp-preview:not(.ytp-tooltip.ytp-preview:not(.ytp-text-detail)) {
                background: var(--main-color);
            }

            .ytp-tooltip.ytp-text-detail .ytp-tooltip-title {
                color: var(--black, var(--white, var(--main-background)));
                opacity: 0.7;
            }

            .ytp-menuitem[aria-checked=true] .ytp-menuitem-toggle-checkbox:not(.ytp-panel-menu):not(.ytp-contextmenu .ytp-menuitem[aria-checked=true] .ytp-menuitem-toggle-checkbox) {
                background: var(--main-color-38);
            }

             .ytp-menuitem-toggle-checkbox {
                background: var(--disabled-color);
                &:after {
                    background: var(--main-text);
                }
            }

            .html5-video-player:not(.ytp-touch-mode) {
                ::-webkit-scrollbar-track,
                ::-webkit-scrollbar {
                    background: none;
                }

                ::-webkit-scrollbar-thumb {
                    background: var(--secondary-text);
                    border: 1px solid var(--button-solid-color);
                    &:hover {
                        background: var(--disabled-color);
                    }
                }
            }

            /* Ambient mode */
            #cinematics.ytd-watch-flexy {
                display: none;
            }

            /* Buttons */
            ytd-guide-entry-renderer[active],
            .ytd-mini-guide-renderer[is-active],
            ytd-compact-link-renderer[compact-link-style=compact-link-style-type-settings-sidebar][active],
            ytd-compact-link-renderer[compact-link-style=compact-link-style-type-settings-sidebar][active]:hover {
                background: var(--main-color);
            }

            ytd-mini-guide-entry-renderer[aria-selected="false"]:not(:hover) {
                background: none;
            }

            a.ytd-mini-guide-entry-renderer {
                padding: 14px 0 14px;
            }

            ytd-guide-entry-renderer[active] .title.ytd-guide-entry-renderer,
            [system-icons][is-active] .title.ytd-mini-guide-entry-renderer,
            ytd-compact-link-renderer[compact-link-style=compact-link-style-type-settings-sidebar][active] [id="label"],
            ytd-guide-entry-renderer[is-header][active] .arrow-icon.ytd-guide-entry-renderer {
                color: var(--black, var(--white, var(--main-background)));
            }

            .yt-spec-touch-feedback-shape__fill {
                background: currentcolor;
            }

            .yt-spec-button-shape-next--mono.yt-spec-button-shape-next--tonal {
                background: var(--button-color);
                color: var(--main-text);
                &:hover {
                    background: var(--button-hover-color);
                }
            }

            .yt-spec-button-shape-next--disabled.yt-spec-button-shape-next--filled {
                background: var(--button-color);
                color: var(--disabled-color);
            }

            .yt-spec-button-shape-next--mono.yt-spec-button-shape-next--outline {
                color: var(--main-text);
                border-color: var(--button-hover-color);
                &:hover {
                    background: var(--button-hover-color);
                    border-color: transparent;
                }
            }

            .yt-spec-button-shape-next--call-to-action.yt-spec-button-shape-next--outline {
                color: var(--main-color);
                border-color: var(--button-hover-color);
                &:hover {
                    background: var(--sugg-action);
                    border-color: transparent;
                }
            }

            .yt-spec-button-shape-next--call-to-action.yt-spec-button-shape-next--tonal {
                color: var(--main-color);
                background-color: var(--sugg-action);
            }

            .yt-spec-button-shape-next--size-m.yt-spec-button-shape-next--segmented-start::after {
                background: var(--button-hover-color);
            }

            .yt-spec-button-shape-next--disabled {
                &.yt-spec-button-shape-next--text {
                    color: var(--disabled-color);
                }
                &.yt-spec-button-shape-next--tonal {
                    color: var(--disabled-color);
                    background: var(--button-color);
                }
            }

            .yt-spec-button-shape-next--call-to-action.yt-spec-button-shape-next--text {
                color: var(--main-color);
                &:hover {
                    background: var(--sugg-action)
                }
            }

            .yt-spec-button-shape-next--filled:is(.yt-spec-button-shape-next--mono, .yt-spec-button-shape-next--overlay, .yt-spec-button-shape-next--call-to-action) {
                background: var(--main-color);
                color: var(--black, var(--white, var(--main-background)));
                &:hover {
                    background: var(--filled-button-hover-color);
                }
            }

            .yt-spec-touch-feedback-shape--touch-response .yt-spec-touch-feedback-shape__stroke {
                border-color: currentcolor
            }

            .yt-spec-button-shape-next--mono.yt-spec-button-shape-next--text {
                color: var(--main-text);
                &:hover {
                    background: var(--button-hover-color);
                }
            }

            #search-clear-button .yt-spec-button-shape-next--mono.yt-spec-button-shape-next--text {
                background: none;
                --yt-spec-touch-response: none;
            }

            yt-chip-cloud-chip-renderer[chip-style=STYLE_DEFAULT][selected],
            yt-chip-cloud-chip-renderer[chip-style=STYLE_HOME_FILTER][selected] {
                background: var(--main-color);
                color: var(--black, var(--white, var(--main-background)));
            }

            yt-icon-button.yt-live-chat-item-list-renderer,
            yt-icon-button.yt-live-chat-item-list-renderer[disabled],
            yt-icon.yt-live-chat-ticker-renderer {
                background: var(--main-color);
                color: var(--black, var(--white, var(--main-background)));
                --yt-spec-touch-response: currentcolor;
            }

            .arrow.ytd-horizontal-card-list-renderer,
            .arrow.yt-horizontal-list-renderer,
            .arrow-container.ytd-video-description-music-section-renderer,
            .arrow.ytd-post-multi-image-renderer,
            .arrow.ytd-merch-shelf-renderer,
            .ytd-horizontal-card-list-renderer[arrow],
            .scroll-button {
                background: var(--button-solid-color);
                box-shadow: 0 4px 4px rgba(0, 0, 0, 0.3), 0 0 4px rgba(0, 0, 0, 0.2);
            }

            .yt-tab-shape-wiz__tab {
                color: var(--secondary-text);
            }

            .yt-tab-shape-wiz__tab--tab-selected {
                color: var(--main-color);
            }

            .yt-tab-group-shape-wiz__slider {
                background: var(--main-color);
            }

            .yt-tab-shape-wiz:hover .yt-tab-shape-wiz__tab-bar {
                background: var(--secondary-text)
            }

            .yt-tab-shape-wiz:focus .yt-tab-shape-wiz__tab {
                color: var(--main-color);
            }

            ytd-guide-entry-renderer[active],
            .ytd-mini-guide-renderer[aria-selected="true"],
            ytd-compact-link-renderer[compact-link-style=compact-link-style-type-settings-sidebar][active] tp-yt-paper-item.ytd-compact-link-renderer {
                --yt-spec-touch-response: var(--black, var(--white, var(--main-background)));
                --paper-item-focused-before-background: var(--black, var(--white, var(--main-background)));
            }

            tp-yt-paper-item[disabled],
            .tp-yt-paper-item.tp-yt-paper-item[disabled] {
                --paper-item-focused-before-background: var(--disabled-color);
            }

            .html5-ypc-purchase {
                background: var(--main-color);
                color: var(--black, var(--white, var(--main-background)));
            }

            .html5-ypc-purchase:hover {
                background: var(--filled-button-hover-color);
            }

            button.ytp-subtitles-button.ytp-button::after {
                background: var(--main-color) !important;
            }

            #voice-search-button .yt-spec-button-shape-next--overlay.yt-spec-button-shape-next--text,
            .yt-spec-button-shape-next--mono + .yt-spec-button-shape-with-label__label {
                color: var(--main-text);
            }

            yt-notification-action-renderer[ui-refresh] yt-icon-button.yt-notification-action-renderer,
            .yt-spec-button-shape-next--mono-inverse.yt-spec-button-shape-next--text {
                color: currentcolor;
                --yt-spec-touch-response: currentcolor;
            }

            .yt-spec-button-shape-next--mono-inverse.yt-spec-button-shape-next--text:hover {
                background: var(--sugg-action-inverse);
            }

            #voice-search-button .yt-spec-button-shape-next--overlay.yt-spec-button-shape-next--text:hover {
                background: var(--button-hover-color);
                --yt-spec-static-overlay-touch-response: var(--main-text);
            }

            yt-live-chat-membership-item-renderer {
                --yt-live-chat-footer-button-text-color: var(--black, var(--white, var(--main-background)));
                --yt-live-chat-footer-button-text-background-color: var(--main-color);
            }

            #icon.ytd-pivot-button-renderer {
                border-color: var(--main-color);
            }

            .ytp-flyout-cta .ytp-flyout-cta-action-button.ytp-flyout-cta-action-button-rounded {
                background: var(--main-color);
                color: var(--black, var(--white, var(--main-background))) !important;
            }

            yt-live-chat-toast-renderer .yt-spec-button-shape-next--call-to-action-inverse.yt-spec-button-shape-next--text {
                color: var(--main-color);
                &:hover {
                    background: var(--sugg-action);
                }
            }

            .yt-spec-button-shape-next--call-to-action-inverse.yt-spec-button-shape-next--text {
                color: var(--black, var(--white, var(--main-background)));
                &:hover {
                    background: var(--sugg-action-inverse);
                }
            }

            /* Live chat */
            #live-chat-dialog-body .bold.yt-formatted-string:not(a) {
                color: var(--main-text) !important;
            }

            yt-live-chat-app ::-webkit-scrollbar-thumb {
                background: var(--secondary-text);
                &:hover {
                    background: var(--disabled-color);
                }
            }

            /* Hyperlinks */            
            .yt-core-attributed-string--link-inherit-color[style*="color: rgb(62"], 
            .yt-core-attributed-string > .yt-core-attributed-string__link--call-to-action-color[rel] {
                color: var(--main-color) !important;
            }

            .yt-core-attributed-string--highlight-text-decorator {
                background: var(--button-color) !important;
            }

            /* Badges/icons */
            .badge-style-type-live-now-alternate.ytd-badge-supported-renderer .yt-icon,
            .badge-style-type-live-now-alternate.ytd-badge-supported-renderer,
            ytd-thumbnail-overlay-time-status-renderer[overlay-style=LIVE] #time-status.ytd-thumbnail-overlay-time-status-renderer {
                color: var(--white, var(--white-2, var(--black, var(--main-background))));
            }

            .yt-spec-icon-badge-shape--type-notification .yt-spec-icon-badge-shape__badge,
            .ytp-videowall-still-info-live,
            .ytp-live-badge[disabled]:before {
                background: var(--red);
                color: var(--white, var(--white-2, var(--black, var(--main-background))));
                border: none;
            }

            .guide-entry-badge.ytd-guide-entry-renderer {
                color: var(--red);
            }

            ytd-guide-entry-renderer[active] .guide-entry-badge {
                color: var(--black, var(--white, var(--main-background)));
            }

            .yt-spec-icon-badge-shape,
            .yt-spec-profile-page-header-information-view-model-shape__profile-page-header-title,
            .yt-spec-icon-badge-shape--style-overlay .yt-spec-icon-badge-shape__icon {
                color: var(--main-text);
            }

            ytd-author-comment-badge-renderer[creator] {
                --ytd-author-comment-badge-background-color: var(--main-color) !important;
                --ytd-author-comment-badge-name-color: var(--black, var(--white, var(--main-background))) !important;
                --ytd-author-comment-badge-icon-color: var(--black, var(--white, var(--main-background))) !important;
            }

            .ytp-settings-button.ytp-hd-quality-badge:after,
            .ytp-settings-button.ytp-hdr-quality-badge:after,
            .ytp-settings-button.ytp-4k-quality-badge:after,
            .ytp-settings-button.ytp-5k-quality-badge:after,
            .ytp-settings-button.ytp-8k-quality-badge:after,
            .ytp-settings-button.ytp-3d-badge-grey:after,
            .ytp-settings-button.ytp-3d-badge:after {
                background-color: var(--main-color-inverted, var(--main-color));
                filter: var(--invert-filter);
            }

            segmented-like-dislike-button-view-model g > g:nth-child(2) path {
                stroke: var(--main-text);
                fill: var(--main-text);
            }

            ytd-subscription-notification-toggle-button-renderer-next path {
                fill: var(--main-text);
            }

            #hearted.ytd-creator-heart-renderer {
                color: var(--red);
            }

            ytd-topbar-logo-renderer [fill="#FF0000"],
            ytd-guide-entry-renderer [fill*="F00"],
            ytd-guide-entry-renderer [fill="red"],
            ytd-offline-promo-renderer [fill*="F00"],
            [class*="shelf-renderer"] [fill="red"],
            #icon.yt-live-chat-viewer-engagement-message-renderer [fill*="F00"],
            .ytp-cued-thumbnail-overlay:hover .ytp-large-play-button-bg,
            ytd-guide-entry-renderer[active] [fill="#FAFAFA"],
            ytd-thumbnail-overlay-downloading-renderer [fill="var(--yt-spec-static-brand-white)"],
            ytd-compact-link-renderer [fill="#CC0000"],
            ytd-member-hub-profile-renderer [fill="#CC0000"],
            ytd-badge-supported-renderer [fill="#CC0000"],
            ytd-consent-bump-v2-lightbox [fill="#FF0000"] {
                fill: var(--main-color);
            }

            ytd-topbar-logo-renderer [fill="white"],
            ytd-guide-entry-renderer [fill="#FAFAFA"],
            ytd-guide-entry-renderer [fill*="#fff"],
            ytd-guide-entry-renderer [fill*="#FFF"]:not([d*="M10"]),
            ytd-guide-entry-renderer[active] [fill*="F00"],
            ytd-offline-promo-renderer [fill="white"],
            [class*="shelf-renderer"] [fill*="#fff"],
            #icon.yt-live-chat-viewer-engagement-message-renderer [fill="#FAFAFA"],
            .ytp-cued-thumbnail-overlay:hover [d*="M 45"],
            ytd-compact-link-renderer [fill="#FFF"],
            ytd-member-hub-profile-renderer [fill="#FFF"],
            ytd-badge-supported-renderer [fill="#FFF"],
            ytd-consent-bump-v2-lightbox [fill="white"] {
                fill: var(--black, var(--white, var(--main-background)));
            }

            /* Pop-up notification */
            yt-notification-action-renderer tp-yt-paper-toast.yt-notification-action-renderer {
                background: var(--main-color);
            }

            yt-notification-action-renderer #text.yt-notification-action-renderer,
            yt-notification-action-renderer #sub-text.yt-notification-action-renderer {
                color: var(--black, var(--white, var(--main-background)));
            }

            /* Skeletons */
            .watch-skeleton .skeleton-bg-color,
            #home-page-skeleton .skeleton-bg-color,
            .masthead-skeleton-icon {
                background: var(--button-color);
            }

            #home-container-skeleton,
            #home-page-skeleton #guide-skeleton,
            #home-chips {
                background: var(--main-backgrond);
                border-color: var(--button-color);
            }

            ytd-masthead.shell.dark,
            ytd-masthead.shell.theater {
                background: var(--main-background) !important;
            }

            .watch-skeleton .skeleton-light-border-bottom {
                border-color: var(--button-color);
            }

            /* Clip creation scrubber view */
            .handle-grip.yt-clip-creation-scrubber-view {
                background: var(--black, var(--white, var(--main-background)));
            }

            /* Emoji picker */
            #emojis.ytd-commentbox {
                --yt-emoji-picker-category-background-color: var(--raised-background);
            }

            yt-emoji-picker-category-button-renderer[active] {
                color: var(--main-color);
            }

            /* Cards */
            .ytp-ce-expanding-overlay-background,
            .yt-ui-ellipsis {
                background: var(--main-background);
            }

            .ytp-ce-channel-this .ytp-ce-channel-metadata {
                border-top: 1px solid var(--button-hover-color);
                color: var(--secondary-text);
            }

            .ytp-sb-subscribe,
            a.ytp-sb-subscribe {
                background: var(--main-color);
                color: var(--black, var(--white, var(--main-background)));
            }

            .ytp-sb-unsubscribe {
                background: var(--button-color);
                color: var(--main-text);
            }

            a.ytp-ce-link,
            a.ytp-ce-link:hover,
            a.ytp-ce-link:visited {
                color: var(--main-color) !important;
            }

            .ytp-ce-element.ytp-ce-force-expand,
            .ytp-ce-element.ytp-ce-element-hover {
                border: 1px solid var(--main-color);
            }

            .ytp-ce-website-metadata,
            .ytp-ce-merchandise-metadata,
            .ytp-ce-merchandise-price-container,
            .ytp-ce-channel-subscribers-text,
            .ytp-ce-channel-metadata {
                color: var(--secondary-text);
            }

            .ytp-ce-website-title,
            .ytp-ce-merchandise-title {
                color: var(--main-text);
            }

            .ytp-exp-ppp-update .ytp-paid-content-overlay-link,
            #avatar.ytd-watch-card-rich-header-renderer {
                border-color: var(--main-color);
            }

            /* Autoplay screen */
            .ytp-autonav-thumbnail-small:hover,
            .ytp-autonav-endscreen-upnext-thumbnail:hover {
                border-color: var(--main-color);
            }

            /* Thanks slider container */
            #sliderBar.tp-yt-paper-slider {
                --paper-slider-container-color: var(--button-color);
            }

            /* Search filters */
            ytd-search-filter-renderer.selected yt-formatted-string.ytd-search-filter-renderer {
                color: var(--main-color);
            }

            /* Progress bar */
            #progress.ytd-flow-step-renderer {
                background: var(--main-color);
            }

            /* Banners */
            ytd-statement-banner-renderer[is-dark-theme] [style*="background-color:rgba(15"] {
                background: none !important;
            }

            ytd-network-status-banner[current-state=OFFLINE] {
                color: var(--main-text);
                background: var(--raised-background);
            }

            ytd-network-status-banner[current-state=BACK_ONLINE] {
                color: var(--black, var(--white, var(--main-background)));
            }

            .ytp-flyout-cta .ytp-flyout-cta-body,
            .ytp-flyout-cta:hover .ytp-flyout-cta-body {
                background: var(--main-background);
            }

            .ytp-flyout-cta .ytp-flyout-cta-headline-container {
                color: var(--main-text);
            }

            .ytp-flyout-cta .ytp-flyout-cta-description-container {
                color: var(--secondary-text);
            }

            /* Text */
            .ytd-brand-video-shelf-renderer:is(#title-container, #subtitle-container),
            [style*="rgb(255"]:is(.yt-core-attributed-string--link-inherit-color, .yt-formatted-string),
            .ytd-menu-title-renderer,
            .page-header-view-model-wiz__page-header-title,
            .yt-video-attribute-view-model__title,
            .profile-page-header-information-view-model-wiz__profile-page-header-title {
                color: var(--main-text) !important;
            }

            .page-header-view-model-wiz__page-header-content-metadata,
            .yt-video-attribute-view-model__subtitle,
            .yt-video-attribute-view-model__secondary-subtitle {
                color: var(--secondary-text);
            }
        }
    }

    if videos-per-row {
        ytd-rich-grid-renderer,
        :root {
            --ytd-rich-grid-items-per-row: videos-per-row !important;
        }

        .ytp-inline-preview-mode .ytp-paid-content-overlay {
            display: none;
        }

        .ytp-inline-preview-ui .ytp-subtitles-button,
        .ytp-inline-preview-ui .ytp-mute-button {
            display: block !important;
        }

        .ytp-inline-preview-mode button.ytp-subtitles-button.ytp-button::after {
            margin: 0 8px;
        }

        ytd-rich-section-renderer {
            order: -1;
        }

        #home-container-media .rich-grid-media-skeleton {
            max-width: "calc(100%/%s - 16px)" % videos-per-row !important;
            min-width: "calc(100%/%s - 16px)" % videos-per-row !important;
        }

        ytd-rich-grid-media[mini-mode] {
            max-width: calc(var(--ytd-rich-grid-items-per-row) * (var(--ytd-rich-grid-item-max-width) + var(--ytd-rich-grid-item-margin)));
        }

        ytd-two-column-browse-results-renderer[page-subtype="channels"]:has(ytd-rich-grid-renderer:not([is-shorts-grid])) {
            width: calc(100% - 32px) !important;
            max-width: calc(var(--ytd-rich-grid-items-per-row) * (var(--ytd-rich-grid-item-max-width) + var(--ytd-rich-grid-item-margin))) !important;
        }

        ytd-rich-item-renderer:nth-child(n + 3):nth-child(-n + {videos-per-row}):has(#video-title.ytd-rich-grid-media)[hidden] {
            display: block !important;
        }

        [style="--ytd-rich-shelf-items-count: 3;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "2";
        }

        [style="--ytd-rich-shelf-items-count: 4;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "3";
        }

        [style="--ytd-rich-shelf-items-count: 5;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "4";
        }

        [style="--ytd-rich-shelf-items-count: 6;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "5";
        }

        [style="--ytd-rich-shelf-items-count: 7;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "6";
        }

        [style="--ytd-rich-shelf-items-count: 8;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "7";
        }

        [style="--ytd-rich-shelf-items-count: 9;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "8";
        }

        [style="--ytd-rich-shelf-items-count: 10;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
            display: none if videos-per-row > "9";
        }

        [style="--ytd-rich-shelf-items-count: 11;"]:has(#video-title.ytd-rich-grid-media) .expand-collapse-button.ytd-rich-shelf-renderer {
